const nodes = input?.["node-instance"] ?? [];

nodes.sort((a, b) => {
  const ta = a?.["start-date"]?.["java.util.Date"] ?? 0;
  const tb = b?.["start-date"]?.["java.util.Date"] ?? 0;
  return ta - tb;
});

const ids = [];

const pushUnique = (id) => {
  if (typeof id !== "number" || id <= 0) return;
  if (!ids.includes(id)) ids.push(id);
};

for (const n of nodes) {
  pushUnique(n["process-instance-id"]);
  if (n["node-type"] === "SubProcessNode") {
    pushUnique(n["reference-id"]);
  }
}

ids

function normalizeDate(ts) {
    if (!ts) return null;
    const d = new Date(ts);
    const pad = n => n.toString().padStart(2, "0");

    return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())} `
         + `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

const rawVars = variables["variable-instance"] || [];

const normalized = rawVars.map(v => {
    const md = v["modification-date"];

    // берём timestamp из java.util.Date
    const ts = md && typeof md === "object"
        ? md["java.util.Date"]
        : null;

    return {
        // переносим все оригинальные поля как есть
        ...v,

        // создаём новые нормализованные поля
        processInstanceId: v["process-instance-id"],
        oldValue: v["old-value"],
        modificationDateTimestamp: ts,
        modificationDate: normalizeDate(ts)
    };
});

{
    variables: normalized,
    svg: svg,
    process: process
}
